public class TemperatureMethods {

    // Define a static method: celsiusToFahrenheit
    // It takes a double parameter and returns a double

    public static void main(String[] args) {
        System.out.println("0C = " + celsiusToFahrenheit(0) + "F");
        System.out.println("100C = " + celsiusToFahrenheit(100) + "F");
        System.out.println("37C = " + celsiusToFahrenheit(37) + "F");
    }
}

